#include <stdio.h>
#include <limits.h>
#define MAX_N 1000
#define MAX_M 10000
#define MAX_K 100
#define INF INT_MAX
int N, M, K;
int S[MAX_M], T[MAX_M], V[MAX_M];
int C[MAX_K];
int dist[MAX_N][MAX_N];
int main() {
    scanf("%d %d %d", &N, &M, &K);
    for (int i = 0; i < M; i++) {
        scanf("%d %d %d", &S[i], &T[i], &V[i]);
    }
    for (int i = 0; i < K; i++) {
        scanf("%d", &C[i]);
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            dist[i][j] = INF;
        }
        dist[i][i] = 0;
    }
    for (int i = 0; i < M; i++) {
        dist[S[i] - 1][T[i] - 1] = V[i];
    }
    for (int k = 0; k < N; k++) {
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }
    }
    for (int i = 0; i < K; i++) {
        int cost = 0;
        for (int j = 0; j < N; j++) {
            for (int k = 0; k < N; k++) {
                if (j != k) {
                    cost += dist[j][k];
                }
            }
        }
        for (int j = 0; j < N; j++) {
            cost += C[i];
        }
        printf("%d\n", cost);
    }
    return 0;
}

